/**
 * @fileoverview Progress barrel.
 * @module module/Progress
 */
import { default as razyui } from '../index.js';
import { ProgressDef as DEF } from './Progress.def.js';
import Progress from './Progress/index.js';

razyui.Progress = Progress;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Progress);
}

export default Progress;

export const stylesheet = null;
