/**
 * @fileoverview Progress view — DOM setup.
 * @module module/Progress/view
 */

import { CLS, PART } from './constants.js';

export function setupDOM(root, config) {
    const { size, variant, value, showLabel } = config;

    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    if (size === 'sm') {
        PART.SM_ROOT.apply(root);
    } else if (size === 'lg') {
        PART.LG_ROOT.apply(root);
    }

    const variantMap = { success: PART.SUCCESS, warning: PART.WARNING, danger: PART.DANGER };
    if (variantMap[variant]) {
        variantMap[variant].apply(root);
    }

    root.setAttr({
        role: 'progressbar',
        'aria-valuemin': '0',
        'aria-valuemax': '100',
        'aria-valuenow': String(value),
    });

    // Label
    let labelEl = null;
    if (showLabel) {
        labelEl = PART.LABEL.create();
        labelEl.text(`${Math.round(value)}%`);
        root.append(labelEl);
    }

    // Track
    const $track = PART.TRACK.create();
    root.append($track);

    // Bar
    const $bar = PART.BAR.create();
    $bar.css('width', `${Math.min(100, Math.max(0, value))}%`);
    $track.append($bar);

    return { trackEl: $track, barEl: $bar, labelEl };
}

export function cleanupDOM(root) {
    root.removeClass(CLS.ROOT);
    root[0].innerHTML = '';
}
